head.script:
/* ★AIcraft guide★    
스크립트 수작업 유의사항
*/


//XXXXXXXXXX The K 프로젝트 패키지 적용 START XXXXXXXXXX//
scwin.strPackageCallYesNo = "N"; //패키지호출여부
scwin.objPackageCustLinkData = "";

scwin.onpageload = function() {
	scwin.OnInitScreen();
};

scwin.onpageunload = function() {}; //패키지고객정보
//XXXXXXXXXX The K 프로젝트 패키지 적용 E N D XXXXXXXXXX//

//**************  TAB clear  ***********************************************************************//

scwin.OnSendKey = async function() {
    if (scwin.Sunap_Check()) {


    } else {
        return;
    }

    //화면 새로고침없이 거래할 경우 기존출력데이타 init (꼭 해주어야함)
    $c.iz.data.setChildData("cleartab_01()", "Panel1");
    $c.iz.data.setChildData("cleartab_02()", "Panel2");
    $c.iz.data.setChildData("cleartab_03()", "Panel3");
    GroupBox6.setValue("");
    GroupBox7.setValue("");
    scrtRelatdNoti.hide();
    scrtRelatdNoti.setValue();
    TAB1.setSelectedTabIndex(0);
    $c.iz.tran.setTranID("KFC0400140");
    await $c.iz.tran.ASend();
    if (hgstAgreAmt.getValue() == 0) {
        LinkText8.hide();
    } else {
        LinkText8.show('');
    }
};



//**************  입력화면 (바로가기)  ****************************************************************//

scwin.LinkText1_OnClick = function(e) {
    //대출금이자및상환예비조회
    Link.acno = acno.getValue();
    Link.exeNo = exeNo.getValue();
    $c.iz.screen.screenOpen("KFC04019000", "DATALINK");
};

scwin.LinkText2_OnClick = function(e) {
    //거래내역조회
    Link.acno = acno.getValue();
    Link.exeNo = exeNo.getValue();
    $c.iz.screen.screenOpen("KFC04011000", "DATALINK");
};

scwin.LinkText3_OnClick = function(e) {
    //계좌적용이율조회
    Link.acno = acno.getValue();
    Link.exeNo = exeNo.getValue();
    $c.iz.screen.screenOpen("KFC04068000", "DATALINK");
};

scwin.LinkText4_OnClick = function(e) {
    //고객종합정보조회
    Link.serchNoDstcd = "2";
    Link.serchNo = acno.getValue();
    $c.iz.screen.screenOpen("KAA04300000", "DATALINK");
};

scwin.LinkText5_OnClick = function(e) {
    //담보내역조회
    Link.inquryDstic = "2";
    Link.scurtyLnbzAcno = acno.getValue();
    $c.iz.screen.screenOpen("KIE04611000", "DATALINK");
};

scwin.LinkText6_OnClick = function(e) {
    //한도조회
    //Link.inquryDstcd = "1";
    //Link.acno = acno.Data;
    $c.iz.screen.screenOpen("KFC04089000", "");
};

scwin.LinkText7_OnClick = function(e) {
    //여신기타조회
    Link.acno = acno.getValue();
    Link.exeNo = exeNo.getValue();
    $c.iz.screen.screenOpen("KFC04002000", "DATALINK");
};

scwin.LinkText7_1_OnClick = function(e) {
    //여신조건변경
    Link.tranKnd = '01';
    Link.acno = acno.getValue();
    $c.iz.screen.screenOpen("KHC05210000", "DATALINK");
};

scwin.LinkText8_OnClick = function(e) {
    //수신 원장조회
    Link.acno = acno.getValue();
    $c.iz.screen.screenOpen("KFA04009000", "DATALINK");
};

scwin.LinkText1_10_OnClick = function(e) {
    //채무자기본정보
    //alert(""+ctcrCustIdnfr.Data.length,"")
    if (ctcrCustIdnfr.getValue().length > 0) {
        //Link.cuniqno = acno.Data;
        //Link.cuniqnoSelct = "1";
        Link.custIdnfr = ctcrCustIdnfr.getValue();
    }
    $c.iz.screen.screenOpen("KIB11100000", "DATALINK");
};

//20150911 적용
scwin.LinkText600_OnClick = function(e) {
    $c.iz.tran.setTranID("KIG11AGBB0");
    //최종여신승인신청번호
    lnbzAthorAplcnNo.setValue(lnbzAthorNo_temp.getValue());
    //대출금액
    $c.iz.tran.setInFDData("KIG11AGBB0", "junalAmt", Math.round(cnpr.getValue()));
    //거래직원번호
    $c.iz.tran.setInFDData("KIG11AGBB0", "junalFnshEmpid", $c.user.getUserProfile('empid'));
    //불할기표차수
    $c.iz.tran.setInFDData("KIG11AGBB0", "patinJunalDgre", 0);
    //대출실행부점
    $c.iz.tran.setInFDData("KIG11AGBB0", "lnExeBrncd", "3377");
    //처리구분
    $c.iz.tran.setInFDData("KIG11AGBB0", "prcssDstcd", "0");
    //SMS 통지여부
    $c.iz.tran.setInFDData("KIG11AGBB0", "sMSNotiYn", "0");
    //거래화면	
    $c.iz.tran.setInFDData("KIG11AGBB0", "tranScrenNo", "KFC04001000");
    $c.iz.tran.WaitSend();
};

//**************  출력부 ***************************************//

scwin.TAB1_OnItemChanged = function(info) {
    // 기본정보
    if (TAB1.getSelectedTabIndex() == "0") {
        if (Panel1.getValue() == "") {
            Panel1.setSrc("KFC04001A01.xml");
            Panel1.BindPanelData("KFC0400140");
        }
    }

    //담보내역,조기상환수수료내역조회,공동차주및실소유자
    if (TAB1.getSelectedTabIndex() == "1") {
        if (Panel2.getValue() == "") {
            Panel2.setSrc("KFC04001A02.xml");
            Panel2.BindPanelData("KFC0400140");
        }
    }
};

scwin.OnEndTran = function() {
    //화면출력
    if ($c.iz._tran.bError == false && outptDstcd.getValue() == "0") {
        GroupBox6.show('');
        GroupBox7.show('');
        TAB1.show('');
        ctrcStusName.setStyle("color", $c.iz.data.getRGBValue(255, 0, 0));
        if (ctrcStusDstcd.getValue() == "1") {
            ctrcStusName.setStyle("color", $c.iz.data.getRGBValue(0, 0, 255));
        }
        /*	      //예금담보인 경우 메세지 출력  (상품대분류 20, 상품중분료 01) 
        	      if( ovrduIrtAplyBaseDd.Data <= User.nowBzoprYmd 
        	         && prdctLagClsfiCd.Data  == "20"
        	         && prdctMedmClsfiCd.Data == "01"
        	         && ctrcStusDstcd.Data == "1"
        	         ){
        		  	scrtRelatdNoti.Data = '이자납입 지연중입니다.';	
        	      //scrtRelatdNoti.ClearData();
        	      	scrtRelatdNoti.Visible = true;

        	      }else{

        	      	scrtRelatdNoti.ClearData();
        	      	scrtRelatdNoti.Visible = false;

        	      //Alert("연체기준일" +ovrduIrtAplyBaseDd.Data+"중분류"+prdctMedmClsfiCd.Data, "확인");
        		  }
        */
        //alert("에러코드"+tran.ErrCd,"");  
        if ($c.iz._tran.errCd == 'N0000016') {
            if (acno.getValue().length > 14 || acno.getValue().substr(1, 1) == 'M') {

            } else {
                Link.inquryDstcd = "1";
                Link.acno = acno.getValue();
                $c.iz.screen.screenOpen("KFC04089000", "DATALINK");
            }
        }
    }
    //장표출력	    
    if ($c.iz._tran.bError == false && outptDstcd.getValue() != "0") {
        GroupBox6.hide();
        GroupBox7.hide();
        scrtRelatdNoti.setValue();
        scrtRelatdNoti.hide();
        TAB1.hide();
    }

    //고객정보번호(관리번호)	      
    if ($c.iz._tran.bError == false && ctcrCustMgtNo.getValue() == '00000') {
        ctcrCustMgtNo.hide();
    }
    if (ctcrCustMgtNo.getValue() != '00000') {
        ctcrCustMgtNo.show('');
    }

    //유동화관련메시지
    if (scrtRelatdNoti.getValue() == "") {
        scrtRelatdNoti.hide();
    } else {
        if (outptDstcd.getValue() != "0") {
            scrtRelatdNoti.setValue();
            scrtRelatdNoti.hide();
        } else {
            scrtRelatdNoti.show('');
            scrtRelatdNoti.setStyle("color", $c.iz.data.getRGBValue(255, 0, 0));
        }
    }

    //금액 init
    if (cncycd.getValue() == "KRW") {
        cnpr.SetDispDecimalPoint(0); //대출금액
        lnExeCutamt.SetDispDecimalPoint(0); //실행금액
        lnBal.SetDispDecimalPoint(0);
        //대출잔액
        hgstAgreAmt.SetDispDecimalPoint(0); //최고약정금액  
    } else {
        cnpr.SetDispDecimalPoint(2); //대출금액
        lnExeCutamt.SetDispDecimalPoint(2); //실행금액
        lnBal.SetDispDecimalPoint(2); //대출잔액
        hgstAgreAmt.SetDispDecimalPoint(2);
    }

    //연체여부
    if (ovrduYn.getValue() == "연체") {
        ovrduYn.setStyle("color", $c.iz.data.getRGBValue(255, 0, 0));
    }
    if (ovrduYn.getValue() == "정상") {
        ovrduYn.setStyle("color", $c.iz.data.getRGBValue(0, 0, 255));
    }

    //미수채권 
    if (uncolcBndAcnStusDstcd.getValue() == "0") {
        uncolcBndAcnStusDstic.setStyle("color", $c.iz.data.getRGBValue(0, 0, 0));
    } else {
        uncolcBndAcnStusDstic.setStyle("color", $c.iz.data.getRGBValue(255, 0, 0));
    }

    //일부상각계좌여부
    if (spare4.getValue() == "여") {
        spare4.setStyle("color", $c.iz.data.getRGBValue(255, 0, 0));
    } else if (spare4.getValue() == "부") {
        spare4.setStyle("color", $c.iz.data.getRGBValue(0, 0, 0));
    }
    imageKey.setValue("");
    // KFC04001A01 화면에서 이미지키 받아오기
    $c.iz.data.setChildData("SendData()", "Panel1");
    if (Link.gdVar != 0) {
        var strKey = Link.imkey;
        if (strKey.substr(9, 3) == "KEY") {
            imageKey.setValue(strKey.substr(15, 37));
        }
    }
    ///////////////////////KB자산유동화적격대출////////////////////////
    // 20-03-311-00026
    // 20-03-312-00021
    // 20-03-314-00011
    // 20-03-317-00008
    // 20-02-116-00009
    //추가 20-03-311-00028(중기)
    // 20-03-312-00022
    // 20-03-314-00012
    // 20-03-317-00011
    // 20-02-116-00012
    //  유동화 적격대출 피담보 채권확정
    //  (기 설정 근저당권 활용제한됨에 유의 및 대출금 완제시 근저당권 해지요망)
    //////////////////////////////////////////////////////////////////////////////
    if (mgtbrn.getValue() == '8961') {
        if ((prdctLagClsfiCd.getValue() == "20" && prdctMedmClsfiCd.getValue() == "03" &&
                ((prdctTmpltCd.getValue() == "311" && (prdctNo.getValue() == "00026" || prdctNo.getValue() == "00028")) ||
                    (prdctTmpltCd.getValue() == "312" && (prdctNo.getValue() == "00021" || prdctNo.getValue() == "00022")) ||
                    (prdctTmpltCd.getValue() == "314" && (prdctNo.getValue() == "00011" || prdctNo.getValue() == "00012")) ||
                    (prdctTmpltCd.getValue() == "317" && (prdctNo.getValue() == "00008" || prdctNo.getValue() == "00011")))) ||
            (prdctLagClsfiCd.getValue() == "20" && prdctMedmClsfiCd.getValue() == "02" && prdctTmpltCd.getValue() == "116" &&
                (prdctNo.getValue() == "00009" || prdctNo.getValue() == "00012"))) {
            $c.iz.data.setChildData('dataBook1.SetCellFontColor(dataBook1.RowCount,0,"#FF0000")', "Panel1");
            $c.iz.data.setChildData('dataBook1.SetCellFontColor(dataBook1.RowCount-1,0,"#FF0000")', "Panel1");
        }
    }
    ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////
    // 조회거래후 실명증표 조회버튼을 Visible 설정값을 정의함
    // 조회버튼 Visible의 True 조건 
    //   1. 조회거래가 정상적으로 수행완료
    //   2. 해당 지점이 현재 일자 기준으로 오픈 대상지점
    //   3. 조회거래 결과값에 실명증표이미지Key값 포함(등록거래시 스캔된 경우)
    //////////////////////////////////////////////////////////////////////////////

    // 실명증표 조회버튼 숨기기 설정
    // 단말 공통 버튼중 8번째 버튼을 사용하지 않은 경우
    $c.iz.data.commonButtonVisible(7, false);

    //조회거래 정상 수행완료 여부 확인
    if ($c.iz._tran.tranId == "KFC0400140" && $c.iz._tran.bError == false) {
        // 해당 지점의 그린뱅크 오픈 여부 확인
        // Return : TRUE(오픈 대상 지점), FALSE(오픈 미대상 지점)
        if ($c.com.critical.checkGreenBankOpen()) {
            //대상 지점이면서 조회거래 결과값에 실명증표이미지Key 포함여부 확인
            if (imageKey.getValue() != "") {
                // 실명증표 조회버튼을 보이도록 설정변경
                $c.iz.data.commonButtonVisible(7, true);
            }
        }
    }

    ///////////////////////GreenBank-실명증표 스캐닝-End//////////////////////////

    //20150911 대출실행확인 추가, 처리대상목록조회(PPT04A11000)에서 호출시 (link 예시)
    //	Link.acno = "78140204095167";
    //	Link.tempScnNo = 'PPT04A11000';
    //	Popup("KFC04001000","DATALINK");
    /* 2020-01-16 정수원님 요청으로 PPT04A11000 -> PPT06K02000으로 변경
      if( User.userBzwkBrncd == "3377" && tempScnNo.value == 'PPT04A11000'){
    */
    if ($c.user.getUserProfile('userBzwkBrncd') == "3377" && tempScnNo.getValue() == 'PPT06K02000') {
        var UserSOD = $c.user.getUserProfile('SOD_ROLE_LIST');
        var ArrUserSOD = UserSOD.split("|");
        for (i = 0; i <= ArrUserSOD.length; i++) {
            if (ArrUserSOD[i] == "20233") {
                //실행버튼 활성화
                LinkText600.show('');
                scwin.Set_change();
            }
        }
    }

    //실행확인 정상 수행완료 여부 확인
    if ($c.iz._tran.tranId == "KIG11AGBB0" && $c.iz._tran.bError == false) {
        // 실행버튼 비활성화
        LinkText600.setDisabled(true);
    } else {
        // 실행버튼 활성화
        LinkText600.setDisabled(false);
    }
    //전자조회표 출력 2016-05-20
    if ($c.iz._tran.bError == false && outptDstcd.getValue() == "4") {
        var imgCustRelnmNo = ssno.getValue(); //고객실명번호(주민번호 앞 6자리)
        var imgCustIdnfr = ctcrCustIdnfr.getValue(); //고객식별자
        var imgCustMgtNo = ctcrCustMgtNo.getValue(); //고객관리번호
        var imgCustnm = custnm.getValue(); //고객명
        // 고객식별자 || 고객번호가 있으면 전자조회표 출력  처리    	
        if (imgCustIdnfr != "" || imgCustRelnmNo != "") {
            $c.iz.data.setAPGlobalData("KMB.IMG_supplInquryNo", "0000000"); // 추가조회번호 (고객정보, 신용보증업무는 "0000000" 입력)

            if (imgCustRelnmNo.length == 13) {
                $c.iz.data.setAPGlobalData("KMB.IMG_custRelnmNo", imgCustRelnmNo.substring(0, 6)); // 고객실명번호 (주민등록번호 앞 6자리)
            } else {
                $c.iz.data.setAPGlobalData("KMB.IMG_custRelnmNo", '000000'); // 사업자 및 법인
            }
            $c.iz.data.setAPGlobalData("KMB.IMG_custIdnfr", imgCustIdnfr); // 고객식별자  
            $c.iz.data.setAPGlobalData("KMB.IMG_custMgtNo", imgCustMgtNo); // 고객관리번호
            $c.iz.data.setAPGlobalData("KMB.IMG_custnm", imgCustnm); // 고객명      
            $c.iz.data.setAPGlobalData("KMB.IMG_elctrInquryKndDstic", "14"); // 전자조회표종류구분 - 14.여신원장조회표
            $c.iz.data.setAPGlobalData("KMB.IMG_cupldYn", ""); // 연동여부
            $c.iz.data.setAPGlobalData("KMB.IMG_formID", "KFC04001000"); // 화면번호
            $c.iz.data.setAPGlobalData("KMB.IMG_elctrFxdfDstcd", "00"); // 전자서식구분


            if ($c.iz.data.getAPGlobalData("KMB.IMG_PBPRDATA") == "" || $c.iz.data.getAPGlobalData("KMB.IMG_elctrFxdfDstcd") == "") {
                var imgMessage = "고객님의 전자조회표 출력 이미지 파일이 없습니다. ";
                imgMessage += "\n검색번호를 다시한번 확인 하신 후 ";
                imgMessage += "\n화면 왼쪽 상단의 출력구분을 확인하여 주십시오";
                $c.iz.data.alert(imgMessage, "안내");
            } else {
                // 전자조회표생성 화면 호출
                //하이픈있는 계좌가 들어오는 경우
                var strAcno1;
                var tempAcno1 = '';
                for (var i = 0; i < acno1.getValue().length; i++) {
                    strAcno1 = acno1.getValue().substr(i, 1);
                    if (strAcno1 != '-') {
                        tempAcno1 += strAcno1;
                    }
                }
                Link.accountNo = tempAcno1; //추가 LINK 
                $c.iz.screen.popup("KMB04990001", "");
            }
        }
    }

    //자동이체계좌번호가 정상이 아닌 경우
    if ($c.iz._tran.tranId == "KFC0400140" && $c.iz._tran.bError == false && aBTAcnDstic.getValue() == '2') {
        var msg = $c.iz.data.confirm("해당 대출계좌와 연결되어 있는 자동이체 계좌가 정상적이지 않습니다. \n\n" + "* '확인' 선택시 자동이체 등록화면[06-75-001]으로 연동됩니다.\n", "자동이체계좌 확인");
        if (msg) {
            Link.drwotAcno11 = aBTAcno.getValue();
            //KJH06101A01.drwotAcno = drwotAcno11.Value ;
            //SetChildData("drwotAcno", "Panel1");

            //SetChildtControlData("drwotAcno.Data", "Link.drwotAcno11", "Panel1", 0); 
            //메인화면의 패널에 데이터 이동은?
            $c.iz.screen.screenOpen("KJH06101000", "DATALINK");
        } else {
            return;
        }
    }
    //통장자동대출확정 미등록 계좌인 경우 팝업문구 안내 : 여신한도운용구분이 3인경우(회전한도(미확정))
    var msgCtnt_temp;
    msgCtnt_temp = msgCtnt.data.substr(0, 1);
    if ($c.iz._tran.tranId == "KFC0400140" && $c.iz._tran.bError == false && msgCtnt_temp == '3') {
