scwin.OnInitScreen = function() {
    //조회목적 자금세탁방지업무(A) 화면에서 삭제

    outptDstcd_2.DeleteItemByKey("A");

    // 대출실행센터인 경우 다른 화면에서 링크된 경우 조회목적을 9:내부업무처리으로 셋팅 2017.06.15
    // 변경 본부부서[01]인 경우 조회목적 SPACE 나머지는 1:고객관리(업무상담) 으로 셋팅 2017.06.21 최종
    if ($c.user.getUserProfile('brcCd') != "01") {
        //12.여신관리센터 인 경우 7:여신관리로 수정
        if ($c.user.getUserProfile('brcCd') == "12") {
            outptDstcd_2.SetCurSel(6);
        } else {
            outptDstcd_2.SetCurSel(0);
        }
    }

    //감사부는 9:내부업무처리로 셋팅 2017.07.04 영업감사부 추가 0223 2019.08.XX
    if ($c.user.getUserProfile('userBzwkBrncd') == "3209" || $c.user.getUserProfile('userBzwkBrncd') == "0223") {
        outptDstcd_2.SetCurSel(8);
    }

    ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////
    // 거래화면이 보여질때 무조건 실명증표 조회버튼을 Visible 설정값을 정의함
    // Visible 설정값은 조회거래의 결과에 따라 속성이 변경됨
    //////////////////////////////////////////////////////////////////////////////

    // 실명증표 조회버튼 숨기기 설정
    $c.iz.data.commonButtonVisible(7, false);

    ///////////////////////GreenBank-실명증표 스캐닝-End//////////////////////////

    //실행버튼 활성화
    LinkText600.hide();
    TAB1.hide();
    GroupBox6.hide();
    GroupBox7.hide();
    scrtRelatdNoti.setValue();
    scrtRelatdNoti.hide();
    Panel1.setSrc("KFC04001A01.xml");
    if (ECB_YN.getValue() == "Y") {
        LinkText1.hide();
        LinkText2.hide();
        LinkText3.hide();
        LinkText4.hide();
        LinkText5.hide();
        LinkText6.hide();
        LinkText7.hide();
    }
    if (acno.getValue() != "") {
        scwin.OnSendKey();
    }

    //XXXXX The K 프로젝트 패키지 적용 START XXXXX//
    if (!scwin.setPackageInit()) {
        // Return : true(패키지 적용), false(패키지 미적용)
        // 패키지 미적용일경우 스크립트 추가


    }
    //XXXXX The K 프로젝트 패키지 적용 E N D XXXXX//

};




