scwin.OnSendKey8 = function() {
    //여기에 구현코드를 삽입하세요.
    ///////////////////////GreenBank-실명증표 스캐닝-Start////////////////////////
    // 조회거래 대상 화면의 공통 버튼 중 실명증표 이미지조회버튼을 선택하여
    // 실명증표 이미지 보기 팝업 화면을 호출함
    //////////////////////////////////////////////////////////////////////////////

    // 실명증표 이미지Key의 존재여부 확인
    if (imageKey.getValue() != "") {
        // 조회결과로 넘겨준 실명증표이미지Key값을 실명증표 이미지조회화면으로 넘겨줌
        // 조회결과에 실명증표이미지Key가 여러개인 경우에는
        // 실명증표이미지Key(37자리)&","&실명증표이미지Key(37자리) 형태로 조합함
        Link.pImageKey = imageKey.getValue();
        // 실명증표이미지 조회화면 팝업으로 호출
        $c.iz.screen.popup("KMB06101100", "DATALINK");
    }
    // 실명증표 이미지Key가 없는 경우 에러메세지를 출력
    else {
        $c.iz.data.alert("조회할 실명증표 이미지가 없습니다.", "실명증표조회");
        // 실명증표 이미지 조회버튼의 속성을 변경하여 버튼을 선택할 수 없도록 처리
        // 단말 공통 버튼중 8번째 버튼을 사용하지 않은 경우
        $c.iz.data.commonButtonVisible(7, false);
    }

    ///////////////////////GreenBank-실명증표 스캐닝-End//////////////////////////

};


scwin.acno_OnValidate = function(info) {
    //하이픈있는 계좌가 들어오는 경우
    var strAcno;
    var tempAcno = '';
    for (var i = 0; i < acno.getValue().length; i++) {
        strAcno = acno.getValue().substr(i, 1);
        if (strAcno != '-') {
            tempAcno += strAcno;
        }
    }
    acno.setValue(tempAcno);
};

