scwin.setPackageInit = function() {
    // 고객맞춤형업무 호출상태 설정
    $c.com.commSetPackageCallState();
    if (scwin.strPackageCallYesNo != "Y") {
        return false;
    }

    // 고객맞춤형업무 연동 데이터 설정
    // CommSetPackageLinkData(실명증표스캔, 디지털서명);
    $c.com.commSetPackageLinkData(false, false);

    // 1. 패키지연동 업무데이터 설정
    acno.setValue(scwin.objPackageCustLinkData.acno); //계좌번호

    // 2. 연동데이터 변경 불가
    // 3. 업무 스크립트 추가

    return true;
};
